mapper.select:
SELECT * FROM dim_nodes
WHERE affiliation_type = #{affiliationType}
ORDER BY update_time DESC

SELECT * FROM dim_nodes
WHERE country = #{country}
ORDER BY update_time DESC

SELECT * FROM dim_nodes
WHERE node_rank = #{nodeRank}
ORDER BY update_time DESC

SELECT * FROM dim_nodes
WHERE mobility_type = #{mobilityType}
ORDER BY update_time DESC

SELECT * FROM dim_nodes
WHERE latitude BETWEEN #{minLat} AND #{maxLat}
AND longitude BETWEEN #{minLon} AND #{maxLon}
AND latitude IS NOT NULL
AND longitude IS NOT NULL
ORDER BY update_time DESC

SELECT * FROM dim_nodes
WHERE first_seen_at > #{firstSeenAfter}
ORDER BY first_seen_at DESC

SELECT dn.node_id as nodeId, dn.callsign, dn.owner, dn.affiliation, dn.affiliation_type as affiliationType, dn.country, dn.continent, dn.is_active as isActive, dn.last_seen as lastSeen, dn.node_rank as nodeRank, dn.mobility_type as mobilityType, dn.first_seen_at as firstSeenAt, dn.latitude, dn.longitude, dn.is_mobile as isMobile, dn.update_time as updateTime, COALESCE(ar.activity_rate_24h, 0.00) as activityRate24h FROM dim_nodes dn LEFT JOIN ( SELECT node_id, ROUND( (SUM(CASE WHEN attr_name = 'is_active' AND new_value = '1' THEN 1 ELSE 0 END) * 100.0) / GREATEST(COUNT(*), 1), 2 ) as activity_rate_24h FROM dwd_node_events_fact WHERE event_time >= DATE_SUB(NOW(), INTERVAL 24 HOUR) AND event_type = 'status_change' AND attr_name = 'is_active' GROUP BY node_id ) ar ON dn.node_id = ar.node_id
AND dn.callsign LIKE CONCAT('%', #{query.callsign}, '%')
AND dn.owner LIKE CONCAT('%', #{query.owner}, '%')
AND dn.affiliation LIKE CONCAT('%', #{query.affiliation}, '%')
AND dn.affiliation_type = #{query.affiliationType}
AND dn.country = #{query.country}
AND dn.continent = #{query.continent}
AND dn.is_active = #{query.isActive}
AND dn.node_rank = #{query.nodeRank}
AND dn.mobility_type = #{query.mobilityType}
AND dn.is_mobile = #{query.isMobile}
ORDER BY
dn.node_id
dn.callsign
dn.country
dn.last_seen
dn.first_seen_at
dn.update_time
ASC
DESC
LIMIT #{query.offset}, #{query.size}

SELECT COUNT(*)
FROM dim_nodes dn


        AND dn.callsign LIKE CONCAT('%', #{query.callsign}, '%')


        AND dn.owner LIKE CONCAT('%', #{query.owner}, '%')


        AND dn.affiliation LIKE CONCAT('%', #{query.affiliation}, '%')


