        AND dn.country = #{query.country}


        AND dn.continent = #{query.continent}


        AND dn.is_active = #{query.isActive}


        AND dn.node_rank = #{query.nodeRank}


        AND dn.mobility_type = #{query.mobilityType}


        AND dn.is_mobile = #{query.isMobile}

SELECT node_id, ROUND( (SUM(CASE WHEN attr_name = 'is_active' AND new_value = '1' THEN 1 ELSE 0 END) * 100.0) / GREATEST(COUNT(*), 1), 2 ) as activityRate FROM dwd_node_events_fact WHERE node_id IN
#{nodeId}
AND event_time >= DATE_SUB(NOW(), INTERVAL 24 HOUR) AND event_type = 'status_change' AND attr_name = 'is_active' GROUP BY node_id
